    TORCH_CHECK(x.size(1) == weight.size(1), "in_channels mismatch");
    TORCH_CHECK(weight.size(2) == 1 && weight.size(3) == 1, "kernel must be 1x1");

    const int64_t N = x.size(0);
    const int64_t C = x.size(1);
    const int64_t H = x.size(2);
    const int64_t W = x.size(3);
    const int64_t OC = weight.size(0);

    at::Tensor y = at::empty({N, OC, H, W}, x.options());
    EXEC_NPU_CMD(aclnnConvPointwise2dCustom, x, weight, y);
    return y;
